INSERT INTO quiz_question (id, vocabulary_word_id, target_level, contextual_cloze, translation, correct_option, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('efef8b78-8f18-54ad-b12b-cbfb7ddde269', '82f91108-38f0-4b1a-b73e-fbaacd6dc557', 'SENIOR_HIGH', 'Since ___ am the leader of this group, I must take responsibility for the project.', '既然我是這個小組的組長，我必須對這個專案負責。', 'I', 'He', 'She', 'They', 'I 是第一人稱單數主格代名詞。', '英文中 I 代表我自己。', '2026-07-05 09:58:22', '2026-07-05 09:58:22'),
('5f1ccb8e-2d92-5d28-aed5-201543d98189', 'a710d4f9-524e-40a3-995c-3321f6ccf13d', 'SENIOR_HIGH', 'Do you ___ any questions regarding the new project?', '關於這個新計畫，你有任何問題嗎？', 'have', 'want', 'make', 'take', 'have (動詞) 表示擁有、具有。', 'have a question = 有問題。', '2026-07-05 09:54:06', '2026-07-05 09:54:06'),
('bc874e66-32ab-53f9-97f9-b6df8c52678d', '91dcf5ec-a9de-490b-a4f5-84248a8f2fa9', 'SENIOR_HIGH', 'Whenever the young boy encounters a difficult problem, ___ seeks advice from his father.', '每當那個男孩遇到困難的問題時，他都會向他的父親尋求建議。', 'he', 'she', 'it', 'they', '指代男性單數主詞。', 'boy → 男性 → he。', '2026-07-06 10:50:11', '2026-07-06 10:50:11'),
('320961d0-36c9-568a-b2e8-4b557acb58dd', 'c0215e23-91f1-4ae9-b39b-b68eff80cb98', 'SENIOR_HIGH', 'The documentary about deep-sea creatures was so ___ that I watched it twice.', '這部關於深海生物的紀錄片非常有趣，以至於我看了兩次。', 'interesting', 'boring', 'tiring', 'confusing', '字首 inter- (在...之間), 字根 est (存在), 字尾 -ing (令人...的)', 'interest (興趣) + ing (令人...的) → interesting (有趣的)', '2026-07-05 05:46:37', '2026-07-05 05:46:37'),
('8b2eba4e-ee29-5284-a4dd-d5a7c0b269b9', '1d86e27e-0866-4c5e-8277-4bc91cc8ab5e', 'SENIOR_HIGH', 'The movie was so boring ___ I fell asleep in the middle.', '這部電影太無聊了，以致於我在中間睡著了。', 'that', 'as', 'since', 'because', '連接詞 (conj.)，常與 so 連用，構成 so...that... (如此...以致於...) 結構。', 'So...that... (如此...以致...)。', '2026-07-05 14:26:52', '2026-07-05 14:26:52'),
('cd819807-f6f1-5558-907f-8c0c3d2665f1', 'a17db9fc-c01a-47c1-8d24-38406a541f61', 'SENIOR_HIGH', 'She has visited the museum many ___ to study the local history.', '她為了研究當地歷史，已經多次造訪這間博物館。', 'times', 'ways', 'places', 'reasons', 'time 作為名詞時，複數形式 times 可表示「次數」。', 'many times 意為「很多次」。', '2026-07-06 11:03:16', '2026-07-06 11:03:16');
